    key = "integer_value";
  }
  if(idx === 0 && val.addConfigFormSelectKey.isVisible && val.addConfigFormSelectKey.isValid) {
    tempObj = {dimension_name: val.addConfigFormSelectKey.value, type: val.addConfigFormSelectDimensionType.vlalue};
    tempObj[`${key}`] = "";
    tempDimensionObj.push(tempObj);
  } else {
    tempObj = {dimension_name: val.addConfigFormTextInputKey.value, type: val.addConfigFormSelectDimensionType.value}
    tempObj[`${key}`] = "";
    tempDimensionObj.push(tempObj);
  }
});
